import{_ as e,c as o,o as t,a as c}from"./app.57713bbf.js";const w=JSON.parse('{"title":"PM2","description":"","frontmatter":{},"headers":[{"level":3,"title":"\u8FDB\u5165\u9879\u76EE\u6839\u76EE\u5F55:","slug":"\u8FDB\u5165\u9879\u76EE\u6839\u76EE\u5F55"},{"level":3,"title":"\u53C2\u6570\u8BF4\u660E\uFF1A","slug":"\u53C2\u6570\u8BF4\u660E\uFF1A"}],"relativePath":"post/tools/pm2.md","lastUpdated":1663768230000}'),d={name:"post/tools/pm2.md"},p=c('<h1 id="pm2" tabindex="-1">PM2 <a class="header-anchor" href="#pm2" aria-hidden="true">#</a></h1><p>pm2\u9700\u8981\u5168\u5C40\u5B89\u88C5</p><p><code>npm install -g pm2</code></p><h3 id="\u8FDB\u5165\u9879\u76EE\u6839\u76EE\u5F55" tabindex="-1">\u8FDB\u5165\u9879\u76EE\u6839\u76EE\u5F55: <a class="header-anchor" href="#\u8FDB\u5165\u9879\u76EE\u6839\u76EE\u5F55" aria-hidden="true">#</a></h3><p>\u542F\u52A8\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 start bin/www \u6216 pm2 start app.js</code></p><p>\u91CD\u547D\u540D\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 start app.js --name wb123</code></p><p>\u6DFB\u52A0\u8FDB\u7A0B/\u5E94\u7528 watch <code>pm2 start bin/www --watch</code></p><p>\u7ED3\u675F\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 stop www</code></p><p>\u7ED3\u675F\u6240\u6709\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 stop all</code></p><p>\u5220\u9664\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 delete www</code></p><p>\u5220\u9664\u6240\u6709\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 delete all</code></p><p>\u5217\u51FA\u6240\u6709\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 list</code></p><p>\u67E5\u770B\u67D0\u4E2A\u8FDB\u7A0B/\u5E94\u7528\u5177\u4F53\u60C5\u51B5 <code>pm2 describe www</code></p><p>\u67E5\u770B\u8FDB\u7A0B/\u5E94\u7528\u7684\u8D44\u6E90\u6D88\u8017\u60C5\u51B5 <code>pm2 monit</code></p><p>\u67E5\u770Bpm2\u7684\u65E5\u5FD7 <code>pm2 logs</code></p><p>\u82E5\u8981\u67E5\u770B\u67D0\u4E2A\u8FDB\u7A0B/\u5E94\u7528\u7684\u65E5\u5FD7,\u4F7F\u7528 <code>pm2 logs www</code></p><p>\u91CD\u65B0\u542F\u52A8\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 restart www</code></p><p>\u91CD\u65B0\u542F\u52A8\u6240\u6709\u8FDB\u7A0B/\u5E94\u7528 <code>pm2 restart all</code></p><h3 id="\u53C2\u6570\u8BF4\u660E\uFF1A" tabindex="-1">\u53C2\u6570\u8BF4\u660E\uFF1A <a class="header-anchor" href="#\u53C2\u6570\u8BF4\u660E\uFF1A" aria-hidden="true">#</a></h3><ul><li><code>--watch</code>\uFF1A\u76D1\u542C\u5E94\u7528\u76EE\u5F55\u7684\u53D8\u5316\uFF0C\u4E00\u65E6\u53D1\u751F\u53D8\u5316\uFF0C\u81EA\u52A8\u91CD\u542F\u3002\u5982\u679C\u8981\u7CBE\u786E\u76D1\u542C\u3001\u4E0D\u89C1\u542C\u7684\u76EE\u5F55\uFF0C\u6700\u597D\u901A\u8FC7\u914D\u7F6E\u6587\u4EF6\u3002</li><li><code>-i --instances</code>\uFF1A\u542F\u7528\u591A\u5C11\u4E2A\u5B9E\u4F8B\uFF0C\u53EF\u7528\u4E8E\u8D1F\u8F7D\u5747\u8861\u3002\u5982\u679C<code>-i 0</code>\u6216\u8005<code>-i max</code>\uFF0C\u5219\u6839\u636E\u5F53\u524D\u673A\u5668\u6838\u6570\u786E\u5B9A\u5B9E\u4F8B\u6570\u76EE\u3002</li><li><code>--ignore-watch</code>\uFF1A\u6392\u9664\u76D1\u542C\u7684\u76EE\u5F55/\u6587\u4EF6\uFF0C\u53EF\u4EE5\u662F\u7279\u5B9A\u7684\u6587\u4EF6\u540D\uFF0C\u4E5F\u53EF\u4EE5\u662F\u6B63\u5219\u3002\u6BD4\u5982<code>--ignore-watch=&quot;test node_modules &quot;some scripts&quot;&quot;</code></li><li><code>-n --name</code>\uFF1A\u5E94\u7528\u7684\u540D\u79F0\u3002\u67E5\u770B\u5E94\u7528\u4FE1\u606F\u7684\u65F6\u5019\u53EF\u4EE5\u7528\u5230\u3002</li><li><code>-o --output </code>\uFF1A\u6807\u51C6\u8F93\u51FA\u65E5\u5FD7\u6587\u4EF6\u7684\u8DEF\u5F84\u3002</li><li><code>-e --error </code>\uFF1A\u9519\u8BEF\u8F93\u51FA\u65E5\u5FD7\u6587\u4EF6\u7684\u8DEF\u5F84\u3002</li><li><code>--interpreter </code>\uFF1Athe interpreter pm2 should use for executing app (bash, python...)\u3002\u6BD4\u5982\u4F60\u7528\u7684coffee script\u6765\u7F16\u5199\u5E94\u7528\u3002</li></ul>',20),a=[p];function s(r,i,l,n,m,h){return t(),o("div",null,a)}var u=e(d,[["render",s]]);export{w as __pageData,u as default};
